test('new user signs up and lands on onboarding', async ({ page }) => {
  await page.goto('/signup');
  await page.fill('#email', 'demo+e2e@acme.dev');
  await page.fill('#password', 'S3cure!pw');
  await page.click('text=Create account');
  await page.click(await mailbox.lastVerifyLink());
  await expect(page).toHaveURL(/\/onboarding/);
});
